import{_ as t,o as n,c as o,ag as a}from"./chunks/framework.DXGyWiRo.js";const i="/images/uebung074.jpg",k=JSON.parse('{"title":"Übung Lektion 45","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung45.md","filePath":"lektionen/uebung45.md"}'),r={name:"lektionen/uebung45.md"};function s(u,e,p,l,c,d){return n(),o("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-45" tabindex="-1">Übung Lektion 45 <a class="header-anchor" href="#ubung-lektion-45" aria-label="Permalink to &quot;Übung Lektion 45&quot;">​</a></h1><p>A) Übersetzen Sie ins Sanskrit (für Vergangenheitsformen bitte das Imperfekt &lt;लङ्&gt; verwenden):</p><p>1. Du spaltest die (buddhistische) Gemeinde.</p><blockquote><p>सङ्घं भिनत्सि ॥१॥</p></blockquote><p>2. Habt ihr die Erde genossen?</p><blockquote><p>किं महीमभुङ्क्त ॥२॥</p></blockquote><p>3. Hast du vom König eine Gabe empfangen?</p><blockquote><p>किं राज्ञो / राज्ञा दानमादत्थाः ॥३॥</p></blockquote><p>4. Heiliger Mann, warum fürchtest du dich nicht vor Gefahren?</p><blockquote><p>साधो कस्माद्भयेभ्यो न बिभेषि ॥४॥</p></blockquote><p>5. Vater, wohin verlässt du die Familie?</p><blockquote><p>पितः कुत्र गच्छन्कुलं जहासि ॥५॥</p></blockquote><p>6. Śūdrafrau, hast du die Last ins Haus des reichen Brahmanen getragen?</p><blockquote><p>शूद्रे ऽपि धनवतो / धनिनो ब्राह्मणस्य गृहं भारमबिभः ॥६॥</p></blockquote><p>7. Göttin, du solltest den Wunsch nach Glück des Vaiśya, der Verdienstvolles getan hat, erfüllen.</p><blockquote><p>देवि कृतपुण्यस्य वैश्यस्य सुखेष्टिं पिपूर्याः ॥७॥</p></blockquote><p>8. Elefanten, ihr solltet die Fesseln nicht zerbrechen.</p><blockquote><p>हस्तिनो बन्धनानि न भञ्ज्यात । भिन्द्यात ॥८॥</p></blockquote><p>9. Du löwengleicher Mann, warum richtest du nicht deine ganze Aufmerksamkeit auf das Absolute (Brahman)?</p><blockquote><p>नरसिंह कस्माद्ब्रह्मणि न समादधासि ॥९॥</p></blockquote><p>10. Hast du, Dichter, die Welten gemessen?</p><blockquote><p>कवे कच्चिल्लोकानमिमीथाः ॥१०॥</p></blockquote><p>B) Übersetzen Sie:</p><p>अर्जुन हतो वा प्राप्स्यसि स्वर्गं जित्वा वा भोक्ष्यसे महीं । तस्माद्भवता योध्यम् ॥१॥</p><blockquote><p>Arjuna!, entweder wirst du getötet und kommst in den Himmel, oder du siegst und wirst die Erde genießen. Deshalb sollst du kämpfen.</p></blockquote><p>भवति कथमनन्तदुःखमरुणत् ॥२॥</p><blockquote><p>Ehrwürdige, wie haben Sie das unendliche Leiden beendet?</p></blockquote><p>ब्राह्मण किमग्नौ घृतमजुहोः ॥३॥</p><blockquote><p>Brahmane, hast du Ghee zum Opfer ins Feuer gegossen?</p></blockquote><p>शत्रो शस्तेण जीवं न छिनत्सि ॥४॥</p><blockquote><p>Feind!, mit dem Schwert spaltest du nicht die Seele.</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: हस्तिनो बन्धनानि न भञ्ज्यात । भिन्द्यात<br> Dubare Elephant Camp, Kodagu = ಕೊಡಗು<br> [Bildquelle: anaxila. -- <a href="http://www.flickr.com/photos/anaxila/412541806/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/anaxila/412541806/</a>. -- Zugriff am 2009-01-22. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Zu den <a href="./uebung46">Lösungen der Übungen 46 - 52</a></p>',34)])])}const m=t(r,[["render",s]]);export{k as __pageData,m as default};
